#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

// 读取命令行参数
const inputPath = process.argv[2];
const outputPath = process.argv[3];

if (!inputPath || !outputPath) {
  console.error('Usage: node ua-tour-analyze.js <input.json> <output.json>');
  process.exit(1);
}

try {
  // 读取输入数据
  const inputData = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
  const { nodes, edges, layers } = inputData;

  // 构建节点索引
  const nodeMap = new Map();
  nodes.forEach(node => {
    nodeMap.set(node.id, node);
  });

  // 构建邻接表（出边和入边）
  const outEdges = new Map(); // node -> [targets]
  const inEdges = new Map();  // node -> [sources]

  nodes.forEach(node => {
    outEdges.set(node.id, []);
    inEdges.set(node.id, []);
  });

  edges.forEach(edge => {
    if (outEdges.has(edge.source)) {
      outEdges.get(edge.source).push(edge.target);
    }
    if (inEdges.has(edge.target)) {
      inEdges.get(edge.target).push(edge.source);
    }
  });

  // A. Fan-In Ranking (Importance)
  const fanInRanking = nodes
    .map(node => ({
      id: node.id,
      name: node.name,
      fanIn: inEdges.get(node.id).length
    }))
    .sort((a, b) => b.fanIn - a.fanIn)
    .slice(0, 20);

  // B. Fan-Out Ranking (Scope)
  const fanOutRanking = nodes
    .map(node => ({
      id: node.id,
      name: node.name,
      fanOut: outEdges.get(node.id).length
    }))
    .sort((a, b) => b.fanOut - a.fanOut)
    .slice(0, 20);

  // C. Entry Point Candidates
  const entryPointCandidates = [];

  const entryFileNames = [
    'index.ts', 'index.js', 'main.ts', 'main.js', 'app.ts', 'app.js',
    'server.ts', 'server.js', 'mod.rs', 'main.go', 'main.py', 'main.rs',
    'manage.py', 'app.py', 'wsgi.py', 'asgi.py', 'run.py', '__main__.py',
    'Application.java', 'Main.java', 'Program.cs', 'config.ru',
    'index.php', 'App.swift', 'Application.kt', 'main.cpp', 'main.c'
  ];

  const fanOutThreshold = fanOutRanking.length > 0 ? fanOutRanking[Math.floor(fanOutRanking.length * 0.1)]?.fanOut || 0 : 0;
  const fanInThreshold = fanInRanking.length > 0 ? fanInRanking[Math.floor(fanInRanking.length * 0.75)]?.fanIn || 0 : 0;

  nodes.forEach(node => {
    let score = 0;

    // 文档文件优先级
    if (node.type === 'document') {
      if (node.name === 'README.md' && node.filePath === 'README.md') {
        score += 5;
      } else if (node.name.endsWith('.md') && node.filePath.split('/').length <= 1) {
        score += 2;
      }
    }

    // 代码文件评分
    if (node.type === 'file') {
      if (entryFileNames.includes(node.name)) {
        score += 3;
      }

      const pathDepth = node.filePath.split('/').length;
      if (pathDepth <= 2) {
        score += 1;
      }

      const fanOut = outEdges.get(node.id).length;
      const fanIn = inEdges.get(node.id).length;

      if (fanOut >= fanOutThreshold) {
        score += 1;
      }

      if (fanIn <= fanInThreshold) {
        score += 1;
      }
    }

    if (score > 0) {
      entryPointCandidates.push({
        id: node.id,
        score: score,
        name: node.name,
        summary: node.summary
      });
    }
  });

  entryPointCandidates.sort((a, b) => b.score - a.score);
  const topEntryPoints = entryPointCandidates.slice(0, 5);

  // D. Dependency Chains (BFS from Entry Points)
  let bfsTraversal = {
    startNode: null,
    order: [],
    depthMap: {},
    byDepth: {}
  };

  // 找到第一个代码入口点（跳过文档节点）
  const codeEntryPoint = topEntryPoints.find(ep => {
    const node = nodeMap.get(ep.id);
    return node.type === 'file';
  });

  if (codeEntryPoint) {
    const startNodeId = codeEntryPoint.id;
    bfsTraversal.startNode = startNodeId;

    const visited = new Set();
    const queue = [{ id: startNodeId, depth: 0 }];
    visited.add(startNodeId);

    while (queue.length > 0) {
      const { id, depth } = queue.shift();
      bfsTraversal.order.push(id);
      bfsTraversal.depthMap[id] = depth;

      if (!bfsTraversal.byDepth[depth]) {
        bfsTraversal.byDepth[depth] = [];
      }
      bfsTraversal.byDepth[depth].push(id);

      // 跟随imports和calls边
      const targets = outEdges.get(id);
      targets.forEach(targetId => {
        if (!visited.has(targetId)) {
          const edge = edges.find(e => e.source === id && e.target === targetId);
          if (edge && (edge.type === 'imports' || edge.type === 'calls')) {
            visited.add(targetId);
            queue.push({ id: targetId, depth: depth + 1 });
          }
        }
      });
    }
  }

  // E. Non-Code File Inventory
  const nonCodeFiles = {
    documentation: [],
    infrastructure: [],
    data: [],
    config: []
  };

  nodes.forEach(node => {
    switch (node.type) {
      case 'document':
        nonCodeFiles.documentation.push({
          id: node.id,
          name: node.name,
          summary: node.summary
        });
        break;
      case 'service':
      case 'pipeline':
      case 'resource':
        nonCodeFiles.infrastructure.push({
          id: node.id,
          name: node.name,
          type: node.type,
          summary: node.summary
        });
        break;
      case 'table':
      case 'schema':
      case 'endpoint':
        nonCodeFiles.data.push({
          id: node.id,
          name: node.name,
          type: node.type,
          summary: node.summary
        });
        break;
      case 'config':
        nonCodeFiles.config.push({
          id: node.id,
          name: node.name,
          summary: node.summary
        });
        break;
    }
  });

  // F. Tightly Coupled Clusters
  const clusters = [];
  const visited = new Set();

  nodes.forEach(nodeA => {
    if (visited.has(nodeA.id)) return;

    const cluster = new Set([nodeA.id]);
    const clusterEdges = new Set();

    // 查找与nodeA有双向关系的节点
    const targetsA = outEdges.get(nodeA.id);
    targetsA.forEach(targetId => {
      const targetsB = outEdges.get(targetId);
      if (targetsB.includes(nodeA.id)) {
        cluster.add(targetId);
        clusterEdges.add(`${nodeA.id}->${targetId}`);
        clusterEdges.add(`${targetId}->${nodeA.id}`);
      }
    });

    // 扩展集群：添加与2+个现有成员连接的节点
    if (cluster.size >= 2) {
      nodes.forEach(candidate => {
        if (cluster.has(candidate.id)) return;

        let connections = 0;
        cluster.forEach(memberId => {
          if (outEdges.get(candidate.id).includes(memberId) ||
              outEdges.get(memberId).includes(candidate.id)) {
            connections++;
          }
        });

        if (connections >= 2) {
          cluster.add(candidate.id);
        }
      });
    }

    if (cluster.size >= 2 && cluster.size <= 5) {
      cluster.forEach(id => visited.add(id));
      clusters.push({
        nodes: Array.from(cluster),
        edgeCount: clusterEdges.size
      });
    }
  });

  clusters.sort((a, b) => b.edgeCount - a.edgeCount);
  const topClusters = clusters.slice(0, 10);

  // G. Layer List
  const layerList = {
    count: layers.length,
    list: layers.map(layer => ({
      id: layer.id,
      name: layer.name,
      description: layer.description
    }))
  };

  // H. Node Summary Index
  const nodeSummaryIndex = {};
  nodes.forEach(node => {
    nodeSummaryIndex[node.id] = {
      name: node.name,
      type: node.type,
      summary: node.summary
    };
  });

  // 输出结果
  const result = {
    scriptCompleted: true,
    entryPointCandidates: topEntryPoints,
    fanInRanking,
    fanOutRanking,
    bfsTraversal,
    nonCodeFiles,
    clusters: topClusters,
    layers: layerList,
    nodeSummaryIndex,
    totalNodes: nodes.length,
    totalEdges: edges.length
  };

  fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  console.log('Analysis completed successfully');
  process.exit(0);

} catch (error) {
  console.error('Error during analysis:', error.message);
  process.exit(1);
}
